mode.example_call:
def analysis = askBob(
    "Analyze these test failures and suggest fixes:\n${reports}",
    'pipeline-test-failure-analyzer'
)

def analysis = askBob(
    "Review these changes for Java best practices and security:\n${diffContent}",
    'solution-code-reviewer'
)

combinations.example:
stages {
    stage('PR Overview') {
        steps {
            script {
                def overview = askBob(
                    "Read git-diff.txt and produce the senior-developer PR overview.",
                    'pipeline-git-diff-overview'
                )
                echo overview
                writeFile file: 'bob-pr-review.md', text: overview
            }
        }
        post { always { archiveArtifacts artifacts: 'bob-pr-review.md', allowEmptyArchive: true } }
    }

    stage('Deep Code Review') {
        when { expression { /* only if the PR is large or risky */ true } }
        steps {
            script {
                def review = askBob(
                    "Review these changes line-by-line:\n${readFile('git-diff.txt')}",
                    'solution-code-reviewer'
                )
                echo review
                writeFile file: 'bob-deep-review.md', text: review
            }
        }
        post { always { archiveArtifacts artifacts: 'bob-deep-review.md', allowEmptyArchive: true } }
    }
}
